INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-06760', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '趙人患鼠，乞貓於中山，中山人予之。貓善捕鼠及雞，月餘，鼠盡而其雞亦盡。其 子患之，告其父曰：「盍去諸？」其父曰：「是非若所知也。吾之患在鼠，不在乎 無雞。夫有鼠則竊吾食，毀吾衣，穿吾垣墉，壞傷吾器用，吾將飢寒焉，不病於無雞 乎？無雞者，弗食雞則已耳，去飢寒猶遠，若之何而去夫貓也。」下列敘述何者最 符合本文意旨？', '["兩害相較，應取其輕", "因小失大，得不償失", "瞻前顧後，左右為難", "投鼠忌器，進退失據"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06761', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「南方多沒人，日與水居也，七歲而能涉，十歲而能浮，十五而能沒矣。夫沒者豈 苟然哉？必將有得於水之道者。日與水居，則十五而得其道，生不識水，則雖壯， 見舟而畏之。故北方之勇者，問於沒人，而求其所以沒，以其言試之河，未有不溺 者也。」透過南方沒人與北方勇者的對比，可以得知：', '["學如不及，猶恐失之", "為學由己，而由人乎哉", "雖有善道，不學不達其功", "真積力久則入，學至乎沒而後止"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06762', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '蘇洵〈管仲論〉文云：「管仲相桓公，霸諸侯，攘戎狄，終其身齊國富強，諸侯不 叛。管仲死，豎刁、易牙、開方用，桓公薨於亂，五公子爭立，其禍蔓延，訖簡公， 齊無寧歲。夫功之成，非成於成之日，蓋必有所由起；禍之作，不作於作之日，亦必 有所由兆。則齊之治也，吾不曰管仲，而曰鮑叔；及其亂也，吾不曰豎刁、易牙、 開方，而曰管仲。何則？豎刁、易牙、開方三子，彼固亂人國者，顧其用之者， 桓公也。夫有舜而後知放四凶，有仲尼而後知去少正卯。彼桓公何人也？顧其使桓 公得用三子者，管仲也。」下列那一選項並非本文所要表達的意涵？', '["個人功過的判斷不應侷限於表象，而應綜觀全體局勢的發展", "齊國之興在於有賢臣能舉才，而齊國之危在於有能臣卻終不能除害", "發現徵兆，防患未然，親賢臣而遠小人，才是國家長治久安的重要基石", "即使管仲才智過人，仍然不能避免禍患產生，令人有「孤臣無力可回天」之感"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06763', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '我國政府在100年社會福利政策綱領中論及社會保險體系的內涵，下列那一個選項是正確的？', '["社會保險給付應依每個人的勞動市場貢獻決定分配比例", "我國社會保險體系應涵蓋健康保險、年金保險、就業保險、職業災害保險、長期照護保險", "在我國目前已開辦的社會保險中，就業保險是最晚開辦的", "我國目前開辦的年金保險，係考量世代間的人口結構而設計不同費率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06764', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社工人員在服務或處置過程中，可能會發生對案主的「反轉移」情形。以下有關反轉移現象的陳述，那 一個選項是不正確的？', '["社工人員對於案主的反轉移與社工人員的早期經驗無關", "社工人員對於案主的反轉移，若未即時覺察，可能對專業關係產生負面影響", "社工人員對於案主的反轉移，若能適當處理，也可能對於服務或治療工作產生正面效益", "社工人員正向看待情感反轉移，自我覺察，有助於減少服務過程中反轉移的發生"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06765', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會正義是社會工作立基的道德基礎。下列何者不是John Rawls論及社會正義的基本原則？', '["任何妨礙追求自己利益和目標的政治權力，是侵犯人權與不正義的", "在社會契約與社會合作的基礎下，每個人都有平等權利享受一個完備體系下的自由保障", "各項職位與社會位置，必須在機會平等原則下，公平的對所有人開放", "基於差異原則，社會處境最不利的成員應優先獲得最大的協助"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06766', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者並非家庭評估的主要目的？', '["社工人員依評估所獲得資訊，判定家庭應該做出那些具體改變", "藉由評估掌握家庭衝突關係，作為提供司法判斷之資訊", "透過評估辨識家庭優勢、能力、家庭與社區資源", "依評估結果，作為擬訂短期與長期處遇目標之基礎"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06767', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '一個家庭的發展往往受社會文化、階級、性別角色及移民因素等影響。下列何者不是屬於影響家庭發展 的文化因素？', '["一個種族或群體的歷史事件與經驗", "家庭在社會中的經濟條件", "一個社會的價值信念體系", "一個社會主張的家庭倫常關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06768', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關探討人們在老化過程如何達到生理與心理適應的相關理論中，認為與社會環境保持活躍互動關係的 老人，較容易成功老化；如果脫離社會活動，則老人可能會較為沮喪以及對老年生活較為不滿。這是以 下那一個理論的觀點？', '["角色理論", "脫離理論", "持續理論", "活動理論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06769', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下何者不屬於家庭系統理論的重要假設？', '["家庭的整體大於其部分的總和", "家庭運作依循著固定規則，以建構及維持家庭成員關係", "家庭中的每個成員都是獨立的個體，必須各自面對問題與解決困難", "不論家庭外在環境如何變化，家庭成員之個體總會試著維持穩定、平衡狀態"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
